                            <p>{__('Go to', 'captain-funnel-for-whatsapp')} <a href="https://developers.facebook.com" target="_blank" rel="noopener noreferrer">developers.facebook.com</a> {__('and log in.', 'captain-funnel-for-whatsapp')}</p>
